use lib_q_hqc::hqc_pke::HqcPke;
use lib_q_hqc::shake256_prng::create_shake256_prng_rng;
use lib_q_hqc::{
    Hqc1Params,
    HqcParams,
};
use rand_core::RngCore;

fn hex_to_bytes(hex: &str) -> Vec<u8> {
    let mut bytes = Vec::new();
    let mut chars = hex.chars().peekable();
    while let (Some(c1), Some(c2)) = (chars.next(), chars.next()) {
        let byte = u8::from_str_radix(&format!("{}{}", c1, c2), 16).unwrap();
        bytes.push(byte);
    }
    bytes
}

#[test]
fn debug_h_vector_generation() {
    // KAT test vector from PQCkemKAT_2321.rsp
    let seed = "9EF877FDDBE8891C6E4E79EAF022E563DEFACA6B152161B9A423E8FE96A403E774B2D352CF74C934069C9DE74757F505";
    let seed_bytes = hex_to_bytes(seed);

    // Expected h vector from KAT (first 1120 bytes of expected public key)
    let expected_pk_hex = "";
    let expected_pk = hex_to_bytes(expected_pk_hex);

    // Extract expected h vector (first 1120 bytes)
    let expected_h = &expected_pk[0..1120];

    // Create SHAKE256 PRNG with test seed for KAT compatibility
    let mut entropy_input = [0u8; 48];
    entropy_input.copy_from_slice(&seed_bytes[..48]);
    let mut rng = create_shake256_prng_rng(entropy_input);

    // Get seed_kem from PRNG (same as KAT test)
    let mut seed_kem = [0u8; 32];
    rng.fill_bytes(&mut seed_kem);

    let pke = HqcPke::<Hqc1Params>::new().unwrap();

    // Derive keypair seeds using hash_i (same as keygen_with_seed)
    let mut keypair_seed = [0u8; 64]; // 2 * SEED_BYTES
    pke.hash_i(&mut keypair_seed, &seed_kem);

    let _seed_dk = &keypair_seed[..32];
    let seed_ek = &keypair_seed[32..];

    println!("=== H VECTOR GENERATION DEBUG ===");
    println!("seed_kem: {:02x?}", seed_kem);
    println!("seed_ek: {:02x?}", seed_ek);
    println!("Expected h (first 32 bytes): {:02x?}", &expected_h[..32]);

    // Generate h using the same method as keygen_with_seed
    let mut ek_xof = lib_q_hqc::internal::shake256::Shake256Xof::new();
    ek_xof.init_with_domain(seed_ek, 1).unwrap();

    let mut h = vec![0u64; Hqc1Params::VEC_N_SIZE_64];
    pke.vect_set_random(&mut ek_xof, &mut h).unwrap();

    // Generate the full public key to get the h vector bytes
    let (pk, _sk) = pke.keygen_with_seed(&seed_kem).unwrap();
    let actual_pk = pk.as_bytes();
    let actual_h_bytes = &actual_pk[0..1120];

    println!(
        "Actual h (first 32 bytes):   {:02x?}",
        &actual_h_bytes[..32]
    );

    // Compare byte by byte
    let mut first_diff = None;
    for (i, (exp, act)) in expected_h.iter().zip(actual_h_bytes.iter()).enumerate() {
        if exp != act {
            first_diff = Some(i);
            break;
        }
    }

    if let Some(idx) = first_diff {
        println!("First difference at byte position: {}", idx);
        println!("Expected: 0x{:02x}", expected_h[idx]);
        println!("Actual:   0x{:02x}", actual_h_bytes[idx]);
        let start = idx.saturating_sub(4);
        let end = (idx + 4).min(expected_h.len());
        println!("Context (bytes {} to {}):", start, end - 1);
        println!("Expected: {:02x?}", &expected_h[start..end]);
        println!("Actual:   {:02x?}", &actual_h_bytes[start..end]);

        // Check if this is a u64 word boundary issue
        let word_idx = idx / 8;
        let byte_in_word = idx % 8;
        println!(
            "This maps to h vector u64 word index: {}, byte within word: {}",
            word_idx, byte_in_word
        );

        if word_idx < h.len() {
            println!(
                "Expected u64 word {}: 0x{:016x}",
                word_idx,
                u64::from_le_bytes([
                    expected_h[word_idx * 8],
                    expected_h[word_idx * 8 + 1],
                    expected_h[word_idx * 8 + 2],
                    expected_h[word_idx * 8 + 3],
                    expected_h[word_idx * 8 + 4],
                    expected_h[word_idx * 8 + 5],
                    expected_h[word_idx * 8 + 6],
                    expected_h[word_idx * 8 + 7],
                ])
            );
            println!("Actual u64 word {}:   0x{:016x}", word_idx, h[word_idx]);
        }
    } else {
        println!("No differences found - h vector matches reference!");
    }
}
